import itertools
class Solution:
    def minimumDeviation(self, nums):
        chains = []
        for x in nums:
            if x % 2 == 1:
                x *= 2
            chain = [x]
            while chain[-1] % 2 == 0:
                chain.append(chain[-1] // 2)
            chains.append(chain)
        best = None
        for combo in itertools.product(*chains):
            d = max(combo) - min(combo)
            if best is None or d < best:
                best = d
        return best

