var minimumDeviation = function(nums) {
    class MaxHeap {
        constructor() { this.a = []; }
        push(v) {
            const a = this.a; a.push(v);
            let i = a.length - 1;
            while (i > 0) {
                const p = (i - 1) >> 1;
                if (a[p] >= a[i]) break;
                [a[p], a[i]] = [a[i], a[p]]; i = p;
            }
        }
        pop() {
            const a = this.a; const top = a[0]; const last = a.pop();
            if (a.length) {
                a[0] = last; let i = 0;
                while (true) {
                    let l = 2 * i + 1, r = 2 * i + 2, m = i;
                    if (l < a.length && a[l] > a[m]) m = l;
                    if (r < a.length && a[r] > a[m]) m = r;
                    if (m === i) break;
                    [a[m], a[i]] = [a[i], a[m]]; i = m;
                }
            }
            return top;
        }
        peek() { return this.a[0]; }
    }
    const heap = new MaxHeap();
    let lo = Infinity;
    for (let x of nums) {
        if (x % 2 === 1) x *= 2;
        heap.push(x);
        lo = Math.min(lo, x);
    }
    let best = heap.peek() - lo;
    while (heap.peek() % 2 === 0) {
        let x = heap.pop();
        x = Math.floor(x / 2);
        lo = Math.min(lo, x);
        heap.push(x);
        best = Math.min(best, heap.peek() - lo);
    }
    return best;
};
